import Foundation

// Transaction protocol to ensure every transaction can generate its unique ID
protocol TransactionProtocol {
    var id: String { get set }
}

struct Transaction<T> where T: TransactionProtocol{
    let transactionItem: T
    
    init(_ item: T){
        self.transactionItem = item
    }
}

// This is a basic example of a financial transaction 
